import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { Plus, X, Tag, Palette, Edit2, Zap } from 'lucide-react'; // Ícone adicional Zap
import ModalFeedback from '../components/ModalFeedback';
import '../styles/Categorias.css';

const Categorias = () => {
  const [categorias, setCategorias] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('despesa');
  const [showModal, setShowModal] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [selectedCat, setSelectedCat] = useState(null);
  
  const [form, setForm] = useState({ nome: '', cor: '#4361ee' });

  useEffect(() => {
    buscarCategorias();
  }, []);

  async function buscarCategorias() {
    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (user) {
        const { data, error } = await supabase
          .from('categorias')
          .select('*')
          .or(`user_id.eq.${user.id},user_id.is.null`) // Mantemos a busca híbrida para segurança
          .order('nome');

        if (error) throw error;
        setCategorias(data || []);
      }
    } catch (error) {
      console.error("Erro ao carregar categorias:", error);
    } finally {
      setLoading(false);
    }
  }

  const openModal = (cat = null) => {
    if (cat) {
      setEditMode(true);
      setSelectedCat(cat);
      setForm({ nome: cat.nome, cor: cat.cor });
    } else {
      setEditMode(false);
      setSelectedCat(null);
      setForm({ nome: '', cor: '#4361ee' });
    }
    setShowModal(true);
  };

  async function handleSalvar(e) {
    e.preventDefault();
    try {
      const { data: { user } } = await supabase.auth.getUser();
      
      //Payload sempre com o ID do usuário logado (Regra Master fixada)
      const payload = { 
        user_id: user.id, 
        nome: form.nome, 
        tipo: activeTab, 
        cor: form.cor 
      };

      if (editMode && selectedCat?.id) {
        const { error } = await supabase
          .from('categorias')
          .update(payload)
          .eq('id', selectedCat.id);
        
        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('categorias')
          .insert([payload]);
        
        if (error) throw error;
      }

      setShowModal(false);
      buscarCategorias();
    } catch (error) {
      alert("Erro ao salvar categoria: " + error.message);
    }
  }

  async function excluirCategoria() {
    if (window.confirm(`Excluir permanentemente a categoria "${form.nome}"?`)) {
      try {
        await supabase.from('categorias').delete().eq('id', selectedCat.id);
        setShowModal(false);
        buscarCategorias();
      } catch (error) {
        console.error("Erro ao excluir:", error);
      }
    }
  }

  const categoriasFiltradas = categorias.filter(c => c.tipo === activeTab);

  return (
    <div className="cat-premium-wrapper fade-in">
      {/* Novo Painel de Cabeçalho Sophisticado */}
      <div className="cat-panel cat-header-panel">
        <div className="cat-header-content">
          <div className="cat-title-area">
            <h1>Gerenciar Categorias</h1>
            <p>Seus rótulos de {activeTab === 'despesa' ? 'Saídas' : 'Entradas'}</p>
          </div>
          <button className="btn-add-cat-desktop" onClick={() => openModal()} title="Nova Categoria">
            <Plus size={20} /> Nova Categoria
          </button>
        </div>
        
        <div className="cat-tab-container-pills">
          <button 
            className={`tab-pill ${activeTab === 'provento' ? 'active' : ''}`} 
            onClick={() => setActiveTab('provento')}
          >
            <ArrowUpCircle size={16}/> Entradas
          </button>
          <button 
            className={`tab-pill ${activeTab === 'despesa' ? 'active' : ''}`} 
            onClick={() => setActiveTab('despesa')}
          >
            <ArrowDownCircle size={16}/> Saídas
          </button>
        </div>
      </div>

      {/* Painel da Lista com Melhoria de Preenchimento */}
      <div className="cat-panel cat-list-panel">
        <div className="panel-inner-header">
            <h3>Lista de Rótulos</h3>
            <Zap size={16} color="#4361ee" />
        </div>
        <div className="cat-list-scrollable">
          {loading ? (
            <div className="cat-status premium">Aguarde, carregando...</div>
          ) : categoriasFiltradas.length > 0 ? (
            categoriasFiltradas.map(cat => (
              <div key={cat.id} className="cat-item-row-premium" onClick={() => openModal(cat)}>
                <div className="cat-item-main">
                  <div className="cat-status-dot" style={{ backgroundColor: cat.cor }}></div>
                  <span className="cat-item-name" style={{ color: cat.cor }}>
                    {cat.nome}
                  </span>
                </div>
                <Edit2 size={16} className="cat-edit-icon" />
              </div>
            ))
          ) : (
            <div className="cat-empty-premium">Nenhuma categoria cadastrada.</div>
          )}
        </div>
      </div>

      {/* FAB Visível apenas no Mobile */}
      <button className="cat-fab mobile-only" onClick={() => openModal()} title="Nova Categoria">
        <Plus size={24} />
      </button>

      {/* Modal - Estilos Mantidos (já estavam bons) */}
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="cat-modal premium fade-in" onClick={e => e.stopPropagation()}>
            <div className="cat-modal-header">
              <h3>{editMode ? 'Editar Categoria' : 'Nova Categoria'}</h3>
              <button onClick={() => setShowModal(false)}><X size={20}/></button>
            </div>

            <form onSubmit={handleSalvar} className="cat-modal-form">
              <div className="cat-input-box">
                <label><Tag size={14}/> Nome</label>
                <input 
                  type="text" required value={form.nome} 
                  onChange={e => setForm({...form, nome: e.target.value})} 
                  placeholder="Ex: Assinaturas..."
                />
              </div>
              
              <div className="cat-input-box">
                <label><Palette size={14}/> Cor</label>
                <div className="cat-color-picker-container">
                   <input 
                    type="color" className="cat-color-input"
                    value={form.cor} 
                    onChange={e => setForm({...form, cor: e.target.value})} 
                  />
                  <input 
                    type="text" className="cat-hex-input"
                    value={form.cor.toUpperCase()}
                    onChange={e => setForm({...form, cor: e.target.value})}
                    maxLength={7}
                  />
                </div>
              </div>

              <div className="cat-modal-actions">
                {editMode && (
                  <button type="button" className="btn-cat-delete" onClick={excluirCategoria}>
                    Excluir
                  </button>
                )}
                <button type="submit" className="btn-cat-save">
                  {editMode ? 'Salvar' : 'Criar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Categorias;
